namespace RecipeHub.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public int TotalRatings { get; set; }
    public int RatingSum { get; set; }
    public double AverageRating => TotalRatings > 0 ? (double)RatingSum / TotalRatings : 0;
}

using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _recipes =
        [
            new Recipe
            {
                Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
                Description = "A simple and delicious pizza with fresh mozzarella, tomatoes, and basil.",
                Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
                Steps = [
                    "Preheat oven to 475°F (245°C) with a pizza stone.",
                    "Stretch dough into a 12-inch round.",
                    "Spread crushed tomatoes over the dough, leaving a 1-inch border.",
                    "Tear mozzarella and distribute evenly.",
                    "Bake for 10–12 minutes until crust is golden.",
                    "Top with fresh basil and a drizzle of olive oil."
                ],
                TotalRatings = 12, RatingSum = 52
            },
            new Recipe
            {
                Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
                Description = "Creamy Roman pasta made with eggs, pecorino, guanciale, and black pepper.",
                Ingredients = ["Spaghetti", "Guanciale (or pancetta)", "Eggs", "Pecorino Romano", "Black pepper"],
                Steps = [
                    "Cook spaghetti in salted boiling water until al dente.",
                    "Cut guanciale into small strips and cook until crispy.",
                    "Whisk eggs with grated pecorino and plenty of black pepper.",
                    "Drain pasta, reserving some pasta water.",
                    "Toss hot pasta with guanciale, then quickly stir in egg mixture off heat.",
                    "Add pasta water as needed for a creamy consistency."
                ],
                TotalRatings = 8, RatingSum = 36
            },
            new Recipe
            {
                Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
                Description = "Tender chicken pieces in a rich, spiced tomato-cream sauce.",
                Ingredients = ["Chicken breast", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger", "Cumin", "Turmeric"],
                Steps = [
                    "Marinate chicken in yogurt, garam masala, and salt for at least 1 hour.",
                    "Grill or broil marinated chicken until charred.",
                    "Sauté onion, garlic, and ginger in a large pan.",
                    "Add spices, then tomato sauce and simmer 15 minutes.",
                    "Stir in cream and add the grilled chicken.",
                    "Simmer 10 minutes and serve with basmati rice or naan."
                ],
                TotalRatings = 15, RatingSum = 68
            },
            new Recipe
            {
                Id = 4, Title = "Vegetable Pad Thai", Category = "Thai",
                Description = "Sweet, sour, and savory stir-fried rice noodles with vegetables and peanuts.",
                Ingredients = ["Rice noodles", "Tofu", "Bean sprouts", "Carrots", "Green onions", "Peanuts", "Tamarind paste", "Fish sauce", "Lime", "Sugar", "Eggs"],
                Steps = [
                    "Soak rice noodles in warm water for 20 minutes, then drain.",
                    "Mix tamarind paste, fish sauce, sugar, and lime juice for the sauce.",
                    "Press and cube tofu, then pan-fry until golden.",
                    "Scramble eggs in the same pan.",
                    "Add noodles, sauce, and vegetables. Stir-fry 3–4 minutes.",
                    "Top with crushed peanuts, bean sprouts, and lime wedges."
                ],
                TotalRatings = 6, RatingSum = 25
            },
            new Recipe
            {
                Id = 5, Title = "Beef Tacos", Category = "Mexican",
                Description = "Seasoned ground beef in warm tortillas with fresh toppings.",
                Ingredients = ["Ground beef", "Taco seasoning", "Corn tortillas", "Lettuce", "Tomatoes", "Cheddar cheese", "Sour cream", "Salsa"],
                Steps = [
                    "Brown ground beef in a skillet, then drain excess fat.",
                    "Add taco seasoning and water, simmer until thickened.",
                    "Warm tortillas in a dry pan or microwave.",
                    "Dice tomatoes and shred lettuce.",
                    "Assemble tacos with beef, lettuce, tomatoes, cheese, sour cream, and salsa."
                ],
                TotalRatings = 10, RatingSum = 42
            },
            new Recipe
            {
                Id = 6, Title = "Miso Ramen", Category = "Japanese",
                Description = "Rich miso-based broth with noodles, soft-boiled egg, and toppings.",
                Ingredients = ["Ramen noodles", "White miso paste", "Chicken broth", "Soy sauce", "Sesame oil", "Soft-boiled eggs", "Corn", "Green onions", "Nori", "Chashu pork (optional)"],
                Steps = [
                    "Bring chicken broth to a simmer.",
                    "Whisk in miso paste, soy sauce, and sesame oil.",
                    "Cook ramen noodles separately according to package directions.",
                    "Prepare soft-boiled eggs (6.5 minutes in boiling water, then ice bath).",
                    "Place noodles in bowls, ladle broth over them.",
                    "Top with halved egg, corn, sliced green onions, nori, and pork if using."
                ],
                TotalRatings = 9, RatingSum = 41
            }
        ];
        _nextId = 7;
    }

    public IReadOnlyList<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().Order().ToList();
    }

    public IReadOnlyList<Recipe> GetByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.TotalRatings++;
            recipe.RatingSum += stars;
        }
    }

    public Recipe AddRecipe(string title, string category, string description, List<string> ingredients, List<string> steps)
    {
        var recipe = new Recipe
        {
            Id = _nextId++,
            Title = title,
            Category = category,
            Description = description,
            Ingredients = ingredients,
            Steps = steps
        };
        _recipes.Add(recipe);
        return recipe;
    }
}

@rendermode InteractiveServer

<div class="star-rating">
    <div class="stars">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span class="star @(star <= (_userRating ?? 0) ? "selected" : "") @(star <= (int)Math.Round(AverageRating) ? "averaged" : "")"
                  @onclick="() => Rate(star)"
                  title="Rate @star star@(star > 1 ? "s" : "")">
                @(star <= (_userRating ?? (int)Math.Round(AverageRating)) ? "★" : "☆")
            </span>
        }
    </div>
    <span class="rating-info">
        @if (_userRating.HasValue)
        {
            <span class="thank-you">Thanks for rating!</span>
        }
        @AverageRating.ToString("0.0") avg · @TotalRatings ratings
    </span>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double AverageRating { get; set; }
    [Parameter] public int TotalRatings { get; set; }
    [Parameter] public EventCallback<int> OnRate { get; set; }

    private int? _userRating;

    private async Task Rate(int stars)
    {
        _userRating = stars;
        await OnRate.InvokeAsync(stars);
    }
}

.star-rating {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    margin: 1rem 0;
}

.stars {
    display: flex;
    gap: 0.15rem;
}

.star {
    font-size: 1.75rem;
    cursor: pointer;
    color: #ccc;
    transition: color 0.15s, transform 0.15s;
    user-select: none;
}

.star:hover {
    transform: scale(1.2);
}

.star.averaged {
    color: #f0a500;
}

.star.selected {
    color: #e8850c;
}

.rating-info {
    font-size: 0.9rem;
    color: #666;
}

.thank-you {
    color: #28a745;
    font-weight: 600;
    margin-right: 0.5rem;
}

