﻿@page "/"
@using RecipeHub.Services
@inject RecipeService RecipeService

<PageTitle>RecipeHub — Recipe Sharing Community</PageTitle>

<div class="hero">
    <h1>🍳 Welcome to RecipeHub</h1>
    <p class="lead">Discover, share, and rate delicious recipes from around the world.</p>
</div>

<h2>Browse by Category</h2>
<div class="category-grid">
    @foreach (var category in RecipeService.GetCategories())
    {
        <a href="category/@category" class="category-card">
            <span class="category-icon">@GetCategoryIcon(category)</span>
            <h3>@category</h3>
            <p>@RecipeService.GetByCategory(category).Count recipe(s)</p>
        </a>
    }
</div>

<div class="cta-section">
    <h2>Have a recipe to share?</h2>
    <p>Join our community and share your favorite recipes with fellow food lovers.</p>
    <a href="submit" class="btn btn-primary btn-lg">Submit a Recipe</a>
</div>

@code {
    private static string GetCategoryIcon(string category) => category switch
    {
        "Italian" => "🍝",
        "Indian" => "🍛",
        "Thai" => "🍜",
        "Mexican" => "🌮",
        "Japanese" => "🍣",
        _ => "🍽️"
    };
}

