﻿@page "/recipe/{RecipeId:int}"
@using RecipeHub.Services
@inject RecipeService RecipeService

<PageTitle>@(_recipe?.Title ?? "Recipe") — RecipeHub</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        @if (_recipe is not null)
        {
            <li class="breadcrumb-item"><a href="category/@_recipe.Category">@_recipe.Category</a></li>
            <li class="breadcrumb-item active">@_recipe.Title</li>
        }
    </ol>
</nav>

@if (_recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>Sorry, we couldn't find that recipe.</p>
}
else
{
    <article class="recipe-detail">
        <h1>@_recipe.Title</h1>
        <span class="badge bg-secondary">@_recipe.Category</span>
        <p class="recipe-description">@_recipe.Description</p>

        <StarRating RecipeId="@_recipe.Id"
                    AverageRating="@_recipe.AverageRating"
                    TotalRatings="@_recipe.TotalRatings"
                    OnRate="HandleRating" />

        <section>
            <h2>🧾 Ingredients</h2>
            <ul class="ingredient-list">
                @foreach (var ingredient in _recipe.Ingredients)
                {
                    <li>@ingredient</li>
                }
            </ul>
        </section>

        <section>
            <h2>👩‍🍳 Steps</h2>
            <ol class="steps-list">
                @foreach (var step in _recipe.Steps)
                {
                    <li>@step</li>
                }
            </ol>
        </section>
    </article>
}

@code {
    [Parameter] public int RecipeId { get; set; }

    private RecipeHub.Models.Recipe? _recipe;

    protected override void OnParametersSet()
    {
        _recipe = RecipeService.GetById(RecipeId);
    }

    private void HandleRating(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        _recipe = RecipeService.GetById(RecipeId);
    }
}

