﻿@page "/category/{CategoryName}"
@using RecipeHub.Services
@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes — RecipeHub</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

<h1>@CategoryName Recipes</h1>

@if (_recipes.Count == 0)
{
    <p>No recipes found in this category.</p>
}
else
{
    <div class="recipe-list">
        @foreach (var recipe in _recipes)
        {
            <a href="recipe/@recipe.Id" class="recipe-card">
                <h3>@recipe.Title</h3>
                <p>@recipe.Description</p>
                <div class="recipe-meta">
                    <span class="rating-badge">★ @recipe.AverageRating.ToString("0.0")</span>
                    <span>@recipe.TotalRatings ratings</span>
                </div>
            </a>
        }
    </div>
}

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;

    private IReadOnlyList<RecipeHub.Models.Recipe> _recipes = [];

    protected override void OnParametersSet()
    {
        _recipes = RecipeService.GetByCategory(CategoryName);
    }
}

﻿@page "/submit"
@rendermode InteractiveServer
@using RecipeHub.Services
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe — RecipeHub</PageTitle>

<h1>📝 Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4>🎉 Recipe submitted!</h4>
        <p>Your recipe "<strong>@_title</strong>" has been added.</p>
        <a href="recipe/@_submittedId">View your recipe →</a>
    </div>
}
else
{
    <EditForm Model="this" OnValidSubmit="HandleSubmit" FormName="submit-recipe" class="recipe-form">
        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" @bind-Value="_title" class="form-control" placeholder="e.g. Grandma's Apple Pie" required />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputText id="category" @bind-Value="_category" class="form-control" placeholder="e.g. Italian, Mexican, Thai" required />
        </div>

        <div class="mb-3">
            <label for="description" class="form-label">Description</label>
            <InputTextArea id="description" @bind-Value="_description" class="form-control" rows="2" placeholder="A brief description of your recipe" required />
        </div>

        <div class="mb-3">
            <label class="form-label">Ingredients</label>
            @for (int i = 0; i < _ingredients.Count; i++)
            {
                var index = i;
                <div class="input-group mb-2">
                    <input type="text" class="form-control" value="@_ingredients[index]"
                           @onchange="e => _ingredients[index] = e.Value?.ToString() ?? string.Empty"
                           placeholder="e.g. 2 cups flour" />
                    @if (_ingredients.Count > 1)
                    {
                        <button type="button" class="btn btn-outline-danger" @onclick="() => _ingredients.RemoveAt(index)">✕</button>
                    }
                </div>
            }
            <button type="button" class="btn btn-outline-secondary btn-sm" @onclick="() => _ingredients.Add(string.Empty)">+ Add ingredient</button>
        </div>

        <div class="mb-3">
            <label class="form-label">Steps</label>
            @for (int i = 0; i < _steps.Count; i++)
            {
                var index = i;
                <div class="input-group mb-2">
                    <span class="input-group-text">@(index + 1).</span>
                    <input type="text" class="form-control" value="@_steps[index]"
                           @onchange="e => _steps[index] = e.Value?.ToString() ?? string.Empty"
                           placeholder="Describe this step..." />
                    @if (_steps.Count > 1)
                    {
                        <button type="button" class="btn btn-outline-danger" @onclick="() => _steps.RemoveAt(index)">✕</button>
                    }
                </div>
            }
            <button type="button" class="btn btn-outline-secondary btn-sm" @onclick="() => _steps.Add(string.Empty)">+ Add step</button>
        </div>

        <button type="submit" class="btn btn-primary btn-lg">Submit Recipe</button>
    </EditForm>
}

@code {
    private string _title = string.Empty;
    private string _category = string.Empty;
    private string _description = string.Empty;
    private List<string> _ingredients = [string.Empty];
    private List<string> _steps = [string.Empty];
    private bool _submitted;
    private int _submittedId;

    private void HandleSubmit()
    {
        var ingredients = _ingredients.Where(i => !string.IsNullOrWhiteSpace(i)).ToList();
        var steps = _steps.Where(s => !string.IsNullOrWhiteSpace(s)).ToList();

        if (string.IsNullOrWhiteSpace(_title) || ingredients.Count == 0 || steps.Count == 0)
            return;

        var recipe = RecipeService.AddRecipe(_title, _category, _description, ingredients, steps);
        _submittedId = recipe.Id;
        _submitted = true;
    }
}

