    border: 1px solid #e0e0e0;
    border-radius: 0.5rem;
    text-decoration: none;
    color: inherit;
    transition: box-shadow 0.15s;
}

.recipe-card:hover {
    box-shadow: 0 2px 8px rgba(0,0,0,0.1);
    text-decoration: none;
    color: inherit;
}

.recipe-card h3 {
    margin: 0 0 0.5rem;
    font-size: 1.15rem;
}

.recipe-card p {
    margin: 0 0 0.5rem;
    color: #555;
}

.recipe-meta {
    display: flex;
    gap: 0.75rem;
    align-items: center;
    font-size: 0.9rem;
    color: #666;
}

.rating-badge {
    color: #f0a500;
    font-weight: 600;
}

.recipe-detail {
    max-width: 700px;
}

.recipe-description {
    font-size: 1.1rem;
